import { Request, Response, Router } from 'express';
import { ZodError } from 'zod';
import { requireAuth } from '../middleware/auth.middleware';
import { dashboardQuerySchema } from '../schemas/financial.schema';
import { getDashboard } from '../services/financial.service';
import { generateStatement } from '../services/financialStatement.service';
import { generateSharableFinancialStatementLink } from '../services/sharableLink.service';
// import { generateSharableFinancialStatementLink } from '../services/sharableLink.service';

export const financialRouter = Router();

financialRouter.use(requireAuth);

financialRouter.get('/dashboard', async (req: Request, res: Response) => {
  const authUser = req.authUser;
  if (!authUser) {
    res.status(401).json({ error: 'Authentication required' });
    return;
  }

  try {
    const { month, year } = dashboardQuerySchema.parse(req.query);
    const result = await getDashboard({
      userId: authUser.id,
      month: month === undefined ? undefined : Number(month),
      year: year === undefined ? undefined : Number(year),
    });
    res.status(200).json(result);
  } catch (error) {
    handleError(res, error);
  }
});

financialRouter.post('/sharable-statement', async (req: Request, res: Response) => {
  const authUser = req.authUser;
  if (!authUser) {
    res.status(401).json({ error: 'Authentication required' });
    return;
  }

  try {
    const { month, year } = dashboardQuerySchema.parse(req.body);
     const statement = await generateStatement({
      userId: authUser.id,
      month: month === undefined ? undefined : Number(month),
      year: year === undefined ? undefined : Number(year),
    });
    const linkToken = await generateSharableFinancialStatementLink(statement.id);
    res.status(200).json({
      token:  linkToken,
    });
  } catch (error) {
    handleError(res, error);
  }
});

const handleError = (res: Response, error: unknown) => {
  if (error instanceof ZodError) {
    res.status(400).json({
      error: 'ValidationError',
      details: error.issues.map((issue) => ({
        field: issue.path.join('.'),
        message: issue.message,
      })),
    });
    return;
  }

  console.error('Failed to compute financial dashboard', error);
  res.status(500).json({ error: 'Internal server error' });
};

