import { AppDataSource } from '../data-source';
import { FinancialStatement as FinancialStatementEntity } from '../entities/financial-statement.entity';
import { User } from '../entities/user.entity';
import { Dashboard, DashboardOptions, getDashboard } from './financial.service';

export type FinancialStatement = {
  id: number;
  user: {
    id: string;
    name: string;
    email: string;
  };
  data: Dashboard;
  createdAt: Date;
};

const statementRepository = AppDataSource.getRepository(FinancialStatementEntity);

export const generateStatement = async (options: DashboardOptions): Promise<FinancialStatement> => {
  const userRepository = AppDataSource.getRepository(User);
  const user = await userRepository.findOne({
    where: {
      id: options.userId,
    },
  });
  if (!user) {
    throw new Error('User not found');
  }
  const dashboard = await getDashboard(options);

  // save statement to database.
  const savedStatement = await statementRepository.save({
    userId: user.id,
    // json
    data: dashboard,
    createdAt: new Date(),
  });

  return {
    id: savedStatement.id,
    user: {
        id: user.id,
        name: user.name,
        email: user.email,
    },
    data: savedStatement.data,
    createdAt: savedStatement.createdAt,
  };
};

