    logging: nodeEnv === 'development',
    entities: [__dirname + '/entities/**/*.{ts,js}'],
    migrations: [__dirname + '/migrations/**/*.{ts,js}'],
  };
};

export const AppDataSource = new DataSource(buildDataSourceOptions());

